            ('lesson-animals-1', 'https://pub-aaf79542519744cfaf424549ccf4588c.r2.dev/videos/D0073.mp4', 78),
            ('lesson-animals-1', 'https://pub-aaf79542519744cfaf424549ccf4588c.r2.dev/videos/W00772B.mp4', 79),
            ('lesson-animals-1', 'https://pub-aaf79542519744cfaf424549ccf4588c.r2.dev/videos/W00602.mp4', 80)
            ), lesson_videos as (
                select distinct on (lesson_id) lesson_id, video_url
                from lesson_video_candidates
                order by lesson_id, order_index
            )
            update "v-sign_schema"."learning_lessons" l
            set video_url = v.video_url,
                updated_at = now()
            from lesson_videos v
            where l.lesson_id = v.lesson_id
            and (l.video_url is null or l.video_url = '');
        end if;
    end
    $$;

